import pick from 'lodash/pick';
import type { FormInternalContextType } from './internal/FormInternalContext';
import {
  useFormInternalContext,
  useFormInternalContextSelector,
  FormInternalContextProvider,
} from './internal/FormInternalContext';

/**
 * @public
 * @typeParam Values - values of this form
 */
export type FormContextType<Values> = Pick<
  FormInternalContextType<Values>,
  | 'values'
  | 'errors'
  | 'touched'
  | 'setValues'
  | 'setFieldsValue'
  | 'setFieldValue'
  | 'setErrors'
  | 'resetErrors'
  | 'setFieldsError'
  | 'setFieldError'
  | 'submit'
  | 'reset'
  | 'isSubmitting'
  | 'isValidating'
  | 'isDirty'
  | 'validateFields'
>;

export const FormContextProvider = FormInternalContextProvider;

/**
 * useFormContextSelector
 * get form context, similar to redux selector
 */
export function useFormContextSelector<Values, Selected>(
  selector: (value: FormContextType<Values>) => Selected,
): Selected {
  return useFormInternalContextSelector(selector);
}

/**
 * useFormContext
 * get from context
 */
export function useFormContext<Values>(): FormContextType<Values> {
  const formInternalCtx = useFormInternalContext<Values>();
  return pick(formInternalCtx, [
    'values',
    'errors',
    'touched',
    'setValues',
    'setFieldsValue',
    'setFieldValue',
    'setErrors',
    'resetErrors',
    'setFieldsError',
    'setFieldError',
    'submit',
    'reset',
    'isSubmitting',
    'isValidating',
    'isDirty',
    'validateFields',
  ]);
}
